<?php
 namespace WPAICG\Vector\Providers\Qdrant\Methods; use WPAICG\Vector\Providers\AIPKit_Vector_Qdrant_Strategy; use WP_Error; if (!defined('ABSPATH')) { exit; } function describe_index_logic(AIPKit_Vector_Qdrant_Strategy $strategyInstance, string $index_name): array|WP_Error { $path = '/collections/' . urlencode($index_name); $description_response = _request_logic($strategyInstance, 'GET', $path); if (is_wp_error($description_response)) { return $description_response; } $result = $description_response['result'] ?? $description_response; if (!is_array($result)) { return new WP_Error('qdrant_describe_malformed', __('Malformed response when describing Qdrant collection.', 'gpt3-ai-content-generator')); } $count_path = '/collections/' . urlencode($index_name) . '/points/count'; $count_body = ['exact' => true]; $count_response = _request_logic($strategyInstance, 'POST', $count_path, $count_body); if (!is_wp_error($count_response) && isset($count_response['count'])) { $result['vectors_count'] = $count_response['count']; } else { if (defined('WP_DEBUG') && WP_DEBUG) { $error_message = is_wp_error($count_response) ? $count_response->get_error_message() : 'Count response malformed.'; } } $result['name'] = $index_name; $result['id'] = $index_name; return $result; }